const j = $json || {};
let md = '';
if (j.message && j.message.content) { md = j.message.content; }
else if (j.content && j.content[0] && j.content[0].text) { md = j.content[0].text; }
else if (typeof j.markdown === 'string') { md = j.markdown; }
md = md || '';
const top = md.split(/\n/).filter(function(l){ return /adnoc|energy|oil|gas|lng|masdar|taqa/i.test(l); }).slice(0,4).join('; ') || 'UAE and ADNOC energy sector developments';
const style = 'Premium editorial intelligence-report cover. Deep navy (#0A1A2F) background with refined gold (#C9A24B) accents. Abstract professional energy motifs. NO text, NO logos, NO faces.';
return [{ json: { markdown: md || 'No data available for this period.', date: new Date().toISOString().slice(0,10), coverPrompt: style + ' Visual theme inspired by: ' + top } }];

let raw = ($json && $json.markdown) || '';
let data = null;
try { data = JSON.parse(raw); } catch (e) {
  try { var m = raw.match(/\{[\s\S]*\}/); if (m) { data = JSON.parse(m[0]); } } catch (e2) { data = null; }
}
const date = ($json && $json.date) || new Date().toISOString().slice(0,10);
function imgDataUri(base){
  const fs = require('fs');
  var tries = [['/config/branding/'+base+'.png','image/png'], ['/config/branding/'+base+'.jpg','image/jpeg'], ['/config/branding/'+base+'.jpeg','image/jpeg']];
  for (var i=0;i<tries.length;i++){ try { var b = fs.readFileSync(tries[i][0]); return 'data:'+tries[i][1]+';base64,'+b.toString('base64'); } catch (e) {} }
  return '';
}
const coverSrc = imgDataUri('cover');
const bannerSrc = imgDataUri('banner');
const avatarSrc = imgDataUri('jarvis-avatar');
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g, function(c){ return ({ '&':'&amp;', '<':'&lt;', '>':'&gt;' })[c]; }); }
function riskColor(r){ r=(r||'').toString().toLowerCase(); if(r.indexOf('high')===0) return '#B02525'; if(r.indexOf('med')===0) return '#B8860B'; if(r.indexOf('low')===0) return '#1E8E5A'; return '#5A6472'; }
function devTable(rows){
  if(!rows || !rows.length) return '<p style="color:#5A6472">No data available for this period.</p>';
  var th = '<tr style="background:#0A1A2F;color:#E7C76A">' + ['Company','Key Development','Strategic Theme','What It Signals','Market Impact / Risk','Watch Point'].map(function(h){ return '<th style="padding:8px;text-align:left;font-size:12px">'+h+'</th>'; }).join('') + '</tr>';
  var trs = rows.map(function(r){ return '<tr style="border-bottom:1px solid #E2E6EC;vertical-align:top">' +
    '<td style="padding:8px;font-weight:600">'+esc(r.company)+'</td>' +
    '<td style="padding:8px">'+esc(r.development)+'</td>' +
    '<td style="padding:8px">'+esc(r.theme)+'</td>' +
    '<td style="padding:8px">'+esc(r.signals)+'</td>' +
    '<td style="padding:8px;color:'+riskColor(r.risk)+';font-weight:600">'+esc(r.risk)+'</td>' +
    '<td style="padding:8px;font-style:italic">'+esc(r.watch)+'</td></tr>'; }).join('');
  return '<table style="border-collapse:collapse;width:100%;font-size:13px;margin:8px 0">'+th+trs+'</table>';
}
function moversTable(rows){
  if(!rows || !rows.length) return '<p style="color:#5A6472">No notable leadership changes this period.</p>';
  var th = '<tr style="background:#0A1A2F;color:#E7C76A">' + ['Company','Individual','Previous role','New role','Effective','Why it matters'].map(function(h){ return '<th style="padding:8px;text-align:left;font-size:12px">'+h+'</th>'; }).join('') + '</tr>';
  var trs = rows.map(function(r){ return '<tr style="border-bottom:1px solid #E2E6EC;vertical-align:top">' +
    '<td style="padding:8px;font-weight:600">'+esc(r.company)+'</td>' +
    '<td style="padding:8px">'+esc(r.individual)+'</td>' +
    '<td style="padding:8px">'+esc(r.previous)+'</td>' +
    '<td style="padding:8px">'+esc(r.current)+'</td>' +
    '<td style="padding:8px">'+esc(r.date)+'</td>' +
    '<td style="padding:8px;font-style:italic">'+esc(r.why)+'</td></tr>'; }).join('');
  return '<table style="border-collapse:collapse;width:100%;font-size:13px;margin:8px 0">'+th+trs+'</table>';
}
function h2(t){ return '<h2 style="color:#0A1A2F;border-left:4px solid #C9A24B;padding-left:10px;font-family:Georgia,serif;font-size:18px;margin-top:26px">'+t+'</h2>'; }
let body;
if (data) {
  var bonus = data.bonus || {};
  body = '<p style="font-size:15px">'+esc(data.intro||'')+'</p>' +
    h2('This week — Middle East NOCs') + devTable(data.noc) +
    h2('This week — Supermajor IOCs') + devTable(data.ioc) +
    h2('Movers &amp; Shakers') + moversTable(data.movers) +
    h2('Bonus Read' + (bonus.title ? (': ' + esc(bonus.title)) : '')) +
    '<div style="font-size:14px;line-height:1.6">'+esc(bonus.body||'').replace(/\n/g,'<br/>')+'</div>';
} else {
  body = '<div style="padding:12px;background:#FDECEC;border:1px solid #B02525;color:#7a1a1a;border-radius:4px">The analyst did not return structured data this run (model output was not valid JSON). Raw output below.</div><pre style="white-space:pre-wrap;font-family:inherit">'+esc(raw)+'</pre>';
}
const weekOf = (data && data.weekOf) ? data.weekOf : date;
const frontCover = coverSrc ? ('<img src="'+coverSrc+'" style="width:100%;display:block"/>') : '';
const masthead = bannerSrc
  ? ('<img src="'+bannerSrc+'" style="width:100%;display:block"/>')
  : ('<div style="background:#0A1A2F;color:#E7C76A;padding:18px;font-family:Georgia,serif;font-size:20px">JARVIS INTELLIGENCE — Weekly Energy Intelligence Brief</div>');
const signoff = avatarSrc
  ? ('<div style="text-align:center;padding:20px;border-top:3px solid #C9A24B;margin-top:16px"><img src="'+avatarSrc+'" style="width:104px;height:104px;border-radius:50%;border:2px solid #C9A24B"/><div style="font-family:Georgia,serif;color:#0A1A2F;margin-top:8px;font-size:14px">Jarvis — AI News Reporter</div></div>')
  : '';
const html = '<!doctype html><meta charset="utf-8"><title>Energy Intelligence Brief — '+esc(weekOf)+'</title>' +
  '<div style="font-family:-apple-system,Segoe UI,Arial,sans-serif;color:#11151c;max-width:980px;margin:0 auto">' +
  frontCover + masthead +
  '<div style="background:#05101F;color:#cdd5e0;padding:6px 18px;font-size:13px">'+esc(weekOf)+' &nbsp;·&nbsp; Confidential</div>' +
  '<div style="padding:18px">'+body+'</div>' +
  signoff + '</div>';
return [{ json: { date: date, html: html, markdown: raw } }];

const fs = require('fs');
const date = $json.date;
const html = $json.html;
const dirs = ['/reports/energy-intelligence', '/reports/archive/energy-intelligence'];
for (var k = 0; k < dirs.length; k++) {
  try { fs.mkdirSync(dirs[k], { recursive: true }); fs.writeFileSync(dirs[k] + '/energy-intelligence-' + date + '.html', html); } catch (e) {}
}
try { fs.writeFileSync('/logs/last-run-success.txt', new Date().toISOString() + ' energy-intelligence'); } catch (e) {}
return [{ json: $json }];

